// Add a new field called 'myNewField' to the JSON of the item
$input.item.json.output = $input.item.json.output.replaceAll("```json","").replaceAll("```","");
$input.item.json.output = JSON.parse($input.item.json.output);

return $input.item;

// 获取上一步传入的数据
const inputData = $input.all();

// 转换每个项目
const outputData = inputData.map(item => {
  const oldPath = item.json.fileName;
  const newPath = oldPath.replace(
    "/home/node/.n8n-files/Videos/", 
    "/MoneyPrinterTurbo/storage/local_videos/"
  );

  return {
    json: {
      provider: "local",
      url: newPath,
      duration: 0
    }
  };
});

// 返回转换后的数据
return outputData;

